module serial2parallel
(
    input clk,
    input rst_n,
    input din_serial,
    input din_valid,
    output reg dout_parallel,
    output reg dout_valid
);
    reg [3:0] cnt;
    reg [7:0] data;

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 4'b0;
            data <= 8'b0;
            dout_parallel <= 8'b0;
            dout_valid <= 1'b0;
        end
        else begin
            if (din_valid) begin
                data <= {data[6:0], din_serial};
                cnt <= cnt + 4'b1;
                if (cnt == 4'b1111) begin
                    dout_parallel <= data;
                    dout_valid <= 1'b1;
                end
                else begin
                    dout_valid <= 1'b0;
                end
            end
            else begin
                dout_valid <= 1'b0;
            end
        end
    end
endmodule
